INSERT INTO `comments` (`id`, `lawsuit_id`, `message`, `created_at`, `updated_at`) VALUES
(30144, 21214, 'הועבר לשמאי ראשי מתן לצורך אישור הסדר', '2025-03-20 05:52:36', '2025-03-20 05:52:36'),
(30145, 21219, 'נפתחה תביעה  AI000813900100 נשלח מייל לצורך קבלת צילומי נזק \r\nהעברתי מייל לאבי שישדר אומדן', '2025-03-20 05:55:39', '2025-03-20 05:55:39'),
(30146, 21189, 'יוסי ביקש לדעת מדוע יש מסגרת שחורה נוספת \r\nבאישור אליה ביטלתי אחת \r\nביטלתי חש\' תיקנתי והוסיפה הנחות', '2025-03-20 06:11:38', '2025-03-20 06:11:38'),
(30147, 21222, 'לאחר שיחה עם טלי המקסימה\r\nסוכם שהכשרה ייצרו קשר הן עם הסוכן קוסאי, והן עם אבו ג\'מאל לצורך דיווח ו68.\r\nנאמר גם שהפוגע אמר לנפגעת שחברת הביטוח הכשרה לא יצרה עימו קשר.\r\nלכן אני מצידי דיברתי עם טלי וסיכמנו שייצרו עימו קשר, ובנוסף אשלח את ההקלטה בה מאשר הפוגע את הפיצוי לנפגעת לירין אצלן', '2025-03-23 09:37:35', '2025-03-23 09:37:35'),
(30148, 21130, 'הלקוח בא לקחת את הצק דודי לא לתת לו-לבדוק שלא היה הנחת הסדר.\r\nמבדיקה הראל קיזיזו 1415 ש\"ח נשלח מייל לויטלי על מה הקיזוז (השמאי יריב)', '2025-03-23 10:32:43', '2025-03-23 10:32:43'),
(30150, 21221, 'נועם ממגדל: אומר שחסר רישיון נהיגה אמרתי לו ששלחתי בחמישי שעבר \r\nאמר שהיו שיפורים של המערכת \r\nוהנושא בטיפול', '2025-03-24 06:20:01', '2025-03-24 06:20:01'),
(30151, 21004, 'בהוראת דודי -נשלח להפקדה-הצק חזר', '2025-03-24 06:25:28', '2025-03-24 06:25:28'),
(30152, 21004, 'הועבר לטיפול עו\"ד ויצמן y@yw-law.co.il  036167732', '2025-03-24 06:26:30', '2025-03-24 06:26:30'),
(30153, 21004, 'עם פלט צק ויפוי כח-מצורף', '2025-03-24 06:33:42', '2025-03-24 06:33:42'),
