(32954, 21625, 'לקוח טופל על ידי דודי \r\nנשלחו מסמכים ותמונות לשמאי על ידי דודי \r\nממתינה להעתק דוח', '2026-05-26 04:07:13', '2026-05-26 04:07:13'),
(32958, 21274, 'אלי מאיילון התקשר רצה לדעת מה מס נגררת ,התקשר בהמשך, אפרת שהסתכל בטופס הודעה.', '2026-05-26 05:34:15', '2026-05-26 05:34:15'),
(32959, 21388, 'צירת קשר עם שמוליק לקוח קיבל פעימה 1בתאריך 20-11-25 ע\"ס 48316 ש\"ח עבור התיקון למוסך בסך 47360 ש\"ח (העבירו בקיזוז 5992 ש\"ח בהודעת תשלום חלקי מפורט קיזוז החלקים) ,בפעימה 2 החזירו את 1/3 המעמ שקוזז הלקוח מתקזז 2/3 מעמ סוכם עם הלקוח מכיוון שהצק של המע\"מ בסך 9439 ש\"ח הופקד לאור הנתונים לא נשתמש בצק שאצלינו ע\"ס 52439 ש\"ח נמצא במרכנתיל אלא יבצע העברה ע\"ס 43604 ש\"ח כשיקבל פעימה 3 אמור להיות בסך 5992 יבצע העברה נוספת.', '2026-05-26 05:57:31', '2026-05-26 05:57:31'),
(32960, 21588, 'תביעה שולמה אתמול \r\nמהלך של פחות מחודש מיום שליחת המסמכים לAIG', '2026-05-26 05:59:14', '2026-05-26 05:59:14'),
(32961, 21588, 'נשלח וואצפ ללקוח ובוצעה שיחה \r\nנאמר כי יבצע בדיקה שאכן נכנס הכסף מAIG ויבצע העברה', '2026-05-26 06:33:53', '2026-05-26 06:33:53');
